SELECT DISTINCT t.* FROM bill_import_data t
INNER JOIN bill_import_record i ON t.bill_import_id = i.id
INNER JOIN bill_users wu ON i.user_id = wu.id
WHERE t.is_archived = false
AND (
    t.person_id IN
    #{id}
    OR wu.person_id IN
    #{id}
    OR EXISTS (
        SELECT 1 FROM person p
        WHERE p.id IN
        #{id}
        AND p.phone_id IS NOT NULL
        AND wu.phone_id IS NOT NULL
        AND p.phone_id = wu.phone_id
    )
    OR t.phone_id IN (
        SELECT pp.phone_id FROM person_phone pp
        WHERE pp.person_id IN
        #{id}
    )
    OR wu.phone_id IN (
        SELECT pp.phone_id FROM person_phone pp
        WHERE pp.person_id IN
        #{id}
    )
)
